namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void SetUp() => _sut = new OrderService();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.Name, Price = e.Price, Quantity = e.Qty }).ToList();

    // ── CreateOrder ─────────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectProperties()
    {
        var items = CreateItems(("Widget", 9.99m, 2), ("Gadget", 24.99m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.AreEqual("cust-1", order.CustomerId);
        CollectionAssert.AreEqual(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("A", 10.00m, 3), ("B", 5.50m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        // 10*3 + 5.5*2 = 41
        Assert.AreEqual(41.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var order = _sut.CreateOrder("cust-1", CreateItems(("X", 1m, 1)));
        var after = DateTime.UtcNow;

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, CreateItems(("X", 1m, 1))));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var items = CreateItems(("X", 1m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // ── GetOrder ────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        var created = _sut.CreateOrder("cust-1", CreateItems(("X", 5m, 1)));

        var retrieved = _sut.GetOrder(created.Id);

        Assert.AreEqual(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ─────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyThatCustomersOrders()
    {
        var o1 = _sut.CreateOrder("alice", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("bob", CreateItems(("B", 2m, 1)));
        var o3 = _sut.CreateOrder("alice", CreateItems(("C", 3m, 1)));

        var aliceOrders = _sut.GetOrdersByCustomer("alice");

        Assert.AreEqual(2, aliceOrders.Count);
        Assert.IsTrue(aliceOrders.Any(o => o.Id == o1.Id));
        Assert.IsTrue(aliceOrders.Any(o => o.Id == o3.Id));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WhenNoneExist_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("nobody");

        Assert.AreEqual(0, result.Count);
    }
}

